import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface Prediccion {
  animal_id: number;
  identificador_unico: string;
  peso_actual: number;
  ganancia_diaria: number;
  dias_para_100kg: number;
  fecha_estimada_venta: string;
  rentabilidad_estimada: number;
}

interface TendenciaProduccion {
  mes: string;
  animales_nacidos: number;
  animales_vendidos: number;
  peso_promedio_venta: number;
  ingresos: number;
}

const Analytics: React.FC = () => {
  const [predicciones, setPredicciones] = useState<Prediccion[]>([]);
  const [tendencias, setTendencias] = useState<TendenciaProduccion[]>([]);
  const [alertasIA, setAlertasIA] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadAnalytics();
  }, []);

  const loadAnalytics = async () => {
    try {
      // Simulación de datos predictivos
      const mockPredicciones: Prediccion[] = [
        {
          animal_id: 1,
          identificador_unico: 'C001',
          peso_actual: 85.5,
          ganancia_diaria: 0.65,
          dias_para_100kg: 22,
          fecha_estimada_venta: '2025-01-15',
          rentabilidad_estimada: 450000
        },
        {
          animal_id: 2,
          identificador_unico: 'C002',
          peso_actual: 78.2,
          ganancia_diaria: 0.58,
          dias_para_100kg: 38,
          fecha_estimada_venta: '2025-01-31',
          rentabilidad_estimada: 420000
        }
      ];

      const mockTendencias: TendenciaProduccion[] = [
        { mes: '2024-10', animales_nacidos: 45, animales_vendidos: 38, peso_promedio_venta: 102.5, ingresos: 15200000 },
        { mes: '2024-11', animales_nacidos: 52, animales_vendidos: 41, peso_promedio_venta: 98.8, ingresos: 16450000 },
        { mes: '2024-12', animales_nacidos: 48, animales_vendidos: 39, peso_promedio_venta: 105.2, ingresos: 17100000 }
      ];

      const mockAlertas = [
        {
          tipo: 'rendimiento_bajo',
          mensaje: 'Animal C045 con ganancia diaria inferior al promedio',
          prioridad: 'media',
          recomendacion: 'Revisar alimentación y estado sanitario'
        },
        {
          tipo: 'oportunidad_venta',
          mensaje: '12 animales próximos al peso óptimo de venta',
          prioridad: 'alta',
          recomendacion: 'Planificar venta en los próximos 15 días'
        },
        {
          tipo: 'eficiencia_reproductiva',
          mensaje: 'Cerda R003 con intervalos entre partos superiores al promedio',
          prioridad: 'media',
          recomendacion: 'Evaluar estado reproductivo y nutricional'
        }
      ];

      setPredicciones(mockPredicciones);
      setTendencias(mockTendencias);
      setAlertasIA(mockAlertas);
    } catch (error) {
      console.error('Error cargando análisis:', error);
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency',
      currency: 'COP'
    }).format(amount);
  };

  const getAlertColor = (prioridad: string) => {
    switch (prioridad) {
      case 'alta': return '#dc3545';
      case 'media': return '#ffc107';
      default: return '#17a2b8';
    }
  };

  if (loading) {
    return (
      <div className="loading">
        <div style={{ fontSize: '48px', marginBottom: '15px' }}>🤖</div>
        <p>Analizando datos con IA...</p>
      </div>
    );
  }

  return (
    <div>
      <div className="mb-3">
        <h1>🤖 Análisis Predictivo e IA</h1>
        <p style={{ color: '#7f8c8d' }}>Inteligencia artificial aplicada a la gestión porcina</p>
      </div>

      {/* Alertas de IA */}
      <div className="card mb-3">
        <h3>🚨 Alertas Inteligentes</h3>
        {alertasIA.length > 0 ? (
          <div>
            {alertasIA.map((alerta, index) => (
              <div key={index} style={{
                padding: '15px',
                marginBottom: '10px',
                borderLeft: `4px solid ${getAlertColor(alerta.prioridad)}`,
                backgroundColor: '#f8f9fa',
                borderRadius: '4px'
              }}>
                <div style={{ 
                  display: 'flex', 
                  justifyContent: 'space-between', 
                  alignItems: 'center',
                  marginBottom: '8px'
                }}>
                  <strong style={{ color: '#2c3e50' }}>{alerta.mensaje}</strong>
                  <span style={{ 
                    fontSize: '12px', 
                    color: getAlertColor(alerta.prioridad),
                    textTransform: 'uppercase',
                    fontWeight: 'bold'
                  }}>
                    {alerta.prioridad}
                  </span>
                </div>
                <p style={{ margin: 0, color: '#6c757d', fontSize: '14px' }}>
                  💡 <strong>Recomendación:</strong> {alerta.recomendacion}
                </p>
              </div>
            ))}
          </div>
        ) : (
          <div style={{ textAlign: 'center', padding: '40px', color: '#28a745' }}>
            <div style={{ fontSize: '48px', marginBottom: '15px' }}>✅</div>
            <p>No hay alertas. Todo funcionando óptimamente.</p>
          </div>
        )}
      </div>

      <div className="grid grid-2">
        {/* Predicciones de Venta */}
        <div className="card">
          <h3>📈 Predicciones de Venta</h3>
          <p style={{ color: '#6c757d', fontSize: '14px', marginBottom: '20px' }}>
            Basado en patrones de crecimiento y machine learning
          </p>
          {predicciones.length > 0 ? (
            <table className="table">
              <thead>
                <tr>
                  <th>Animal</th>
                  <th>Peso Actual</th>
                  <th>Días para 100kg</th>
                  <th>Rentabilidad Est.</th>
                </tr>
              </thead>
              <tbody>
                {predicciones.map((pred, index) => (
                  <tr key={index}>
                    <td style={{ fontWeight: 'bold' }}>{pred.identificador_unico}</td>
                    <td>{pred.peso_actual} kg</td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        backgroundColor: pred.dias_para_100kg <= 30 ? '#d4edda' : '#fff3cd',
                        color: pred.dias_para_100kg <= 30 ? '#155724' : '#856404',
                        fontSize: '12px'
                      }}>
                        {pred.dias_para_100kg} días
                      </span>
                    </td>
                    <td style={{ color: '#28a745', fontWeight: 'bold' }}>
                      {formatCurrency(pred.rentabilidad_estimada)}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p style={{ textAlign: 'center', color: '#666', padding: '20px' }}>
              No hay datos suficientes para predicciones
            </p>
          )}
        </div>

        {/* Tendencias de Producción */}
        <div className="card">
          <h3>📊 Tendencias de Producción</h3>
          <p style={{ color: '#6c757d', fontSize: '14px', marginBottom: '20px' }}>
            Análisis de patrones históricos y proyecciones
          </p>
          {tendencias.length > 0 ? (
            <table className="table">
              <thead>
                <tr>
                  <th>Mes</th>
                  <th>Nacidos</th>
                  <th>Vendidos</th>
                  <th>Ingresos</th>
                </tr>
              </thead>
              <tbody>
                {tendencias.map((tend, index) => (
                  <tr key={index}>
                    <td>{tend.mes}</td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        backgroundColor: '#e3f2fd',
                        color: '#1976d2',
                        fontSize: '12px'
                      }}>
                        {tend.animales_nacidos}
                      </span>
                    </td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        backgroundColor: '#f3e5f5',
                        color: '#7b1fa2',
                        fontSize: '12px'
                      }}>
                        {tend.animales_vendidos}
                      </span>
                    </td>
                    <td style={{ color: '#28a745', fontWeight: 'bold', fontSize: '14px' }}>
                      {formatCurrency(tend.ingresos)}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p style={{ textAlign: 'center', color: '#666', padding: '20px' }}>
              Recopilando datos históricos...
            </p>
          )}
        </div>
      </div>

      {/* Métricas de IA */}
      <div className="grid grid-4 mt-3">
        <div className="card text-center">
          <div style={{ fontSize: '32px', marginBottom: '10px' }}>🎯</div>
          <h4 style={{ color: '#2c3e50', marginBottom: '10px' }}>Precisión IA</h4>
          <div style={{ fontSize: '24px', color: '#28a745', marginBottom: '5px' }}>94.2%</div>
          <p style={{ color: '#7f8c8d', margin: 0, fontSize: '12px' }}>Predicciones de peso</p>
        </div>

        <div className="card text-center">
          <div style={{ fontSize: '32px', marginBottom: '10px' }}>⚡</div>
          <h4 style={{ color: '#2c3e50', marginBottom: '10px' }}>Eficiencia</h4>
          <div style={{ fontSize: '24px', color: '#17a2b8', marginBottom: '5px' }}>+12%</div>
          <p style={{ color: '#7f8c8d', margin: 0, fontSize: '12px' }}>vs. gestión manual</p>
        </div>

        <div className="card text-center">
          <div style={{ fontSize: '32px', marginBottom: '10px' }}>💰</div>
          <h4 style={{ color: '#2c3e50', marginBottom: '10px' }}>Ahorro</h4>
          <div style={{ fontSize: '24px', color: '#28a745', marginBottom: '5px' }}>$2.3M</div>
          <p style={{ color: '#7f8c8d', margin: 0, fontSize: '12px' }}>Último trimestre</p>
        </div>

        <div className="card text-center">
          <div style={{ fontSize: '32px', marginBottom: '10px' }}>🔮</div>
          <h4 style={{ color: '#2c3e50', marginBottom: '10px' }}>Predicciones</h4>
          <div style={{ fontSize: '24px', color: '#6f42c1', marginBottom: '5px' }}>156</div>
          <p style={{ color: '#7f8c8d', margin: 0, fontSize: '12px' }}>Generadas este mes</p>
        </div>
      </div>

      {/* Información sobre IA */}
      <div className="card mt-3">
        <h3>🧠 Sobre la Inteligencia Artificial</h3>
        <div className="grid grid-3">
          <div>
            <h4 style={{ color: '#2c3e50', marginBottom: '10px' }}>Algoritmos Utilizados</h4>
            <ul style={{ color: '#6c757d' }}>
              <li>Regresión lineal para predicción de peso</li>
              <li>Redes neuronales para patrones reproductivos</li>
              <li>Análisis de series temporales</li>
              <li>Clustering para segmentación de animales</li>
            </ul>
          </div>
          <div>
            <h4 style={{ color: '#2c3e50', marginBottom: '10px' }}>Datos Analizados</h4>
            <ul style={{ color: '#6c757d' }}>
              <li>Historial de pesajes y crecimiento</li>
              <li>Patrones reproductivos</li>
              <li>Datos sanitarios y tratamientos</li>
              <li>Variables ambientales</li>
            </ul>
          </div>
          <div>
            <h4 style={{ color: '#2c3e50', marginBottom: '10px' }}>Beneficios</h4>
            <ul style={{ color: '#6c757d' }}>
              <li>Optimización de recursos</li>
              <li>Detección temprana de problemas</li>
              <li>Mejora en toma de decisiones</li>
              <li>Incremento de rentabilidad</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Analytics;
